import React from 'react';
import { trainings } from '../../data/mockData';
import TrainingCard from '../../components/TrainingCard';

export default function MyTrainings() {
  // Mocking the user being enrolled in 1 training program
  const myTrainings = trainings.slice(0, 1);

  return (
    <div className="page-enter">
      <h1 className="dashboard-title">My Active Trainings</h1>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: '24px' }}>
        {myTrainings.map(t => (
          <div key={t.id}>
             {/* Note: In a real app we might pass a different prop for "enrolled view" */}
            <TrainingCard training={t} /> 
            <button className="btn btn-mint" style={{ width: '100%', marginTop: '12px' }}>Resume Course →</button>
          </div>
        ))}
      </div>
    </div>
  );
}
